import{_ as o,o as t,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"3. Notice Of Termination Employer","description":"","frontmatter":{"title":"3. Notice Of Termination Employer","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages","employment","termination"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/employment-types/3-notice-of-termination-employer.md","filePath":"ebas/has-managers-admin/managers-admin/employment-types/3-notice-of-termination-employer.md"}'),r={name:"ebas/has-managers-admin/managers-admin/employment-types/3-notice-of-termination-employer.md"};function a(s,e,p,m,l,h){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_3-notice-of-termination-employer" tabindex="-1">3. Notice Of Termination Employer <a class="header-anchor" href="#_3-notice-of-termination-employer" aria-label="Permalink to &quot;3. Notice Of Termination Employer&quot;">​</a></h1><p><strong>3.1</strong> The Employer must not terminate an Employee’s employment unless they have given the Employee written notice of the day of the termination (which cannot be before the day the notice is given).</p><p><strong>3.2</strong> In order to terminate the employment of an Employee, the Employer will give 4 weeks written notice, or pay one month’s wages in lieu of notice.</p><p><strong>3.3</strong> The period of notice in subclause 3.2 will be increased by one week if the Employee is over 45 years of age and has completed at least 2 years continuous service with the Employer at the end of the day the notice is given.</p><p><strong>3.4</strong> For the purposes of this clause:</p><p><strong>(a)</strong> a period of service by an Employee with an Employer is a period during which the Employee is Employed by the Employer, but not including any period of unauthorised absence; and</p><p><strong>(b)</strong> a period of unauthorised absence does not break an Employee’s continuous service with an Employer, but is not to be counted towards the length of the Employee’s continuous service.</p><p><strong>3.5</strong> A transferring Employee’s period of continuous service includes each period of continuous service of the Employee with an old Employer in the business being transferred (whether or not the old Employer was previously a new Employer in connection with the business). However, the Employee’s continuous service with an old Employer is disregarded so far as the Employee had previously received notice of termination, or payment in lieu of such notice, in respect of that service.</p><p><strong>3.6</strong> The Employer must not terminate the Employee’s employment unless:</p><p><strong>(a)</strong> the time between giving the notice and the day of the termination is at least the period (the minimum period of notice) worked out under this clause 3; or</p><p><strong>(b)</strong> the Employer has paid the Employee payment in lieu of notice of at least the amount the Employer would have been liable to pay the Employee at the full rate of pay for the hours he or she would have worked had the employment continued until the end of the minimum period of notice;</p><p><strong>(c)</strong> provided that the employment may be terminated by part of the period of notice specified and part payment in lieu thereof.</p><p><strong>3.7</strong> Notice of termination will not apply in the case of dismissal for serious and wilful misconduct.</p><p><strong>3.8</strong> Where an Employer has given notice of termination to an Employee, the Employee will be allowed up to one days’ time off without loss of pay for the purpose of seeking other employment. The time off will be taken at times that are convenient to the Employee, following consultation with the Employer.</p>',14)])])}const y=o(r,[["render",a]]);export{d as __pageData,y as default};
